from pydantic_ai import Agent
from vex_sdk import VexMonitor

def detect_token_spikes(agent: Agent):
    baseline_tokens = 150  # Expected for simple queries

    @VexMonitor(metric='token_cost')
    def monitored_run(query: str):
        result = agent.run_sync(query)
        tokens_used = result.usage.total_tokens
        if tokens_used > baseline_tokens * 3:
            raise ValueError(f"Token spike detected: {tokens_used} vs {baseline_tokens}")
        return result

    return monitored_run

from pydantic_ai import Agent

class RetryTracker:
    def __init__(self):
        self.retry_counts = 0

    def track_retries(self, agent: Agent):
        original_run = agent.run_sync

        def tracked_run(*args, **kwargs):
            self.retry_counts += 1
            if self.retry_counts > 2:
                print(f"⚠️ Excessive retries: {self.retry_counts}")
            return original_run(*args, **kwargs)

        agent.run_sync = tracked_run
        return self

import json
from pydantic_ai import Agent

def scan_output_verbosity(agent: Agent, query: str):
    result = agent.run_sync(query)
    output_size = len(json.dumps(result.model_dump()))

    if output_size > 1000:
        print(f"🚨 Verbose output: {output_size} chars")
        print(f"Sample: {json.dumps(result.model_dump())[:200]}...")
    else:
        print(f"✅ Efficient: {output_size} chars")

    return {'size': output_size, 'efficient': output_size <= 500}

